const body = $input.first().json.body || $input.first().json || {};
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const sessionUuid = body.session_uuid || body.metadata?.session_uuid || body.raw_payload?.session_uuid || null;
const conversationId = body.conversation_id || body.conversationId || body.raw_payload?.conversation_id || body.raw_payload?.conversationId || null;
const transcript = typeof body.transcript === 'string' ? body.transcript.trim() : '';
const summary = typeof body.summary === 'string' && body.summary.trim()
  ? body.summary.trim()
  : (transcript ? transcript.split('\n').slice(0, 3).join(' ').slice(0, 280) : null);
const lines = transcript.split('\n').map((line) => line.trim()).filter(Boolean);
const extractAnswerAfter = (questionRegex) => {
  const questionIndex = lines.findIndex((line) => line.startsWith('agent:') && questionRegex.test(line.toLowerCase()));
  if (questionIndex === -1) return null;
  for (let i = questionIndex + 1; i < lines.length; i += 1) {
    if (lines[i].startsWith('user:')) return lines[i].replace(/^user:\s*/i, '').trim();
  }
  return null;
};
const cleanField = (value) => value ? value.replace(/[.。]+$/g, '').trim() : null;
const splitPainPoints = (value) => {
  if (!value) return [];
  return value
    .split(/,| och | samt /i)
    .map((item) => item.replace(/^eh\s+/i, '').trim())
    .filter(Boolean)
    .slice(0, 8);
};
const personName = cleanField(extractAnswerAfter(/vad heter du/));
const companyAnswer = cleanField(extractAnswerAfter(/vad heter f[öo]retaget/));
const industryAnswer = cleanField(extractAnswerAfter(/vilken bransch/));
const painPointAnswer = cleanField(extractAnswerAfter(/vad tar mest tid|mest friktion/));
const currentProcessAnswer = cleanField(extractAnswerAfter(/hur hanterar ni allt det d[äa]r idag/));
const emailMatch = transcript.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const extractedData = {
  person_name: personName,
  company_name: companyAnswer,
  industry: industryAnswer,
  email: emailMatch ? emailMatch[0].toLowerCase() : null,
  pain_points: splitPainPoints(painPointAnswer),
  pain_points_summary: painPointAnswer,
  current_process: currentProcessAnswer,
  meeting_requested: /bokar? gärna ett möte|boka in|kalenderinbjudan|google meet-länk/i.test(transcript),
};
const errors = [];
if (!sessionUuid) errors.push('session_uuid required');
if (sessionUuid && !uuidRegex.test(sessionUuid)) errors.push('session_uuid must be valid UUID');
if (!conversationId) errors.push('conversation_id required');
if (errors.length) {
  return [{ json: { validation_failed: true, message: errors.join('; ') } }];
}
return [{
  json: {
    validation_failed: false,
    session_uuid: sessionUuid,
    external_call_id: conversationId,
    provider: 'elevenlabs',
    call_source: body.source || 'voice_call_ended',
    agent_id: body.agent_id || body.agentId || null,
    started_at: body.started_at || body.startedAt || null,
    ended_at: body.ended_at || body.endedAt || new Date().toISOString(),
    duration_seconds: body.duration_seconds || body.durationSeconds || null,
    transcript,
    summary,
    recording_url: body.recording_url || body.recordingUrl || null,
    extracted_data: extractedData,
    metadata: body.metadata || {},
    raw_payload: body.raw_payload || body
  }
}];

const normalized = $('Normalize Call Payload').first().json;
const rows = $input.first().json;
const prospect = Array.isArray(rows) ? rows[0] : null;
return [{
  json: {
    ...normalized,
    prospect_id: prospect?.id || null,
    customer_id: prospect?.customer_id || null
  }
}];
